// mdEditorData returns the Alpine.js x-data object for the markdown editor.
// Uses String.fromCharCode(96,96,96) to produce ``` without conflicting with Go raw strings.
func mdEditorData() string {
	return `{
		tab: 'write',
		insertMd(before, after) {
			const ta = this.$refs.mded;
			if (!ta) return;
			const s = ta.selectionStart, e = ta.selectionEnd;
			const sel = ta.value.substring(s, e);
			ta.value = ta.value.substring(0, s) + before + sel + after + ta.value.substring(e);
			ta.selectionStart = s + before.length;
			ta.selectionEnd = s + before.length + sel.length;
			ta.focus();
		},
		insertLine(prefix) {
			const ta = this.$refs.mded;
			if (!ta) return;
			const s = ta.selectionStart;
			const lineStart = ta.value.lastIndexOf('\n', s - 1) + 1;
			ta.value = ta.value.substring(0, lineStart) + prefix + ta.value.substring(lineStart);
			ta.selectionStart = ta.selectionEnd = s + prefix.length;
			ta.focus();
		},
		insertBlock() {
			const ta = this.$refs.mded;
			if (!ta) return;
			const fence = String.fromCharCode(96, 96, 96);
			const s = ta.selectionStart, e = ta.selectionEnd;
			const sel = ta.value.substring(s, e);
			const block = fence + '\n' + sel + '\n' + fence;
			ta.value = ta.value.substring(0, s) + block + ta.value.substring(e);
			ta.selectionStart = s + fence.length + 1;
			ta.selectionEnd = s + fence.length + 1 + sel.length;
			ta.focus();
		}
	}`
}

// mdRows converts RowCount to a CSS min-height string.
func mdRows(f *MarkdownEditorInput) string {
	rows := f.RowCount
	if rows <= 0 {
		rows = 10
	}
	return strconv.Itoa(rows*24) + "px"
}

